INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('fdfccbcc-9ab9-4fab-ad56-0fcd16a69a6f', '33538287-6906-41c9-852a-9491f20e6c57', 'A minimalist abstract generated art piece, inspired by Tyler Hobbs'' ''Fidenza''. Thousands of colorful, fluid, interlocking curves and blocks (teal, coral, gold, white) create an intricate, flowing texture against a clean white background. No explicit shapes, only raw pattern and color Harmony. Generative art style, high resolution.', 'flux-2-flex', '3:4', '4K', 'https://pub-8742eaa8e7ce488ba306c3dc5bacddd1.r2.dev/images/1775716180523-1775716180523-0.png', '2026-04-09T06:29:42.246Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('2f1838da-0bf5-43c4-894e-ddd47a56434e', '33538287-6906-41c9-852a-9491f20e6c57', 'A hyper-detailed gold coin, the front featuring a regal Shiba Inu (Doge style) wearing a tiny, sparkling royal crown. He has a majestic, confident expression. The reverse is an elaborate engraving of a rocket ship aiming at a massive crescent moon. Set on a dark velvet background with scattered diamonds. Photorealistic macro photography, dramatic chiaroscuro lighting, 8k.', 'doubao-seedream-4-5', '3:4', '4K', 'https://pub-8742eaa8e7ce488ba306c3dc5bacddd1.r2.dev/images/1775716123567-1775716123566-0.png', '2026-04-09T06:28:44.526Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('85bfe750-6b97-4875-a4f0-009f3556928e', '33538287-6906-41c9-852a-9491f20e6c57', 'An anime-style portrait of a wide-eyed girl with a nostalgic 2000s internet aesthetic. She has messy blonde hair, wearing a designer beret and a vintage luxury brand coat with strange patterns. The background is a lo-fi glitchy city street with Japanese typography and glowing butterflies. Flat cel-shading, vibrant yet slightly washed-out colors, dreamcore atmosphere.', 'doubao-seedream-4-5', '2:3', '4K', 'https://pub-8742eaa8e7ce488ba306c3dc5bacddd1.r2.dev/images/1775702444755-1775702444755-0.png', '2026-04-09T02:40:48.644Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('26ac3819-e7d5-4066-a7e7-60fd5361ab2c', '33538287-6906-41c9-852a-9491f20e6c57', 'A majestic oil painting of a noble frog king (Pepe style) in Renaissance attire, sitting on a throne made of emeralds and gold. He has a smug yet serene expression. The background is an opulent palace hall with stained glass windows showing Bitcoin symbols. Rich textures, masterful brushwork, dramatic chiaroscuro lighting, museum-quality art.', 'doubao-seedream-5-0', '2:3', '4K', 'https://pub-8742eaa8e7ce488ba306c3dc5bacddd1.r2.dev/images/1775697880428-1775697880428-0.png', '2026-04-09T01:24:42.168Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('6016cfcd-e676-400b-a23d-85dc3a3ec910', '33538287-6906-41c9-852a-9491f20e6c57', 'A portrait of a digital cyberpunk character, pixel art style but with modern voxel depth. An alien with light blue skin wearing small shades and a dark hoodie, smoking a digital pipe that exhales binary code smoke. Dark background with flickering green matrix-style lights. Low-fi aesthetic, vibrant cyan and magenta highlights, retro-futuristic.', 'doubao-seedream-5-0', '3:4', '4K', 'https://pub-8742eaa8e7ce488ba306c3dc5bacddd1.r2.dev/images/1775697838122-1775697838122-0.png', '2026-04-09T01:23:59.376Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('331f6b8b-e1ed-42dd-aa07-648d1fdd73b6', '33538287-6906-41c9-852a-9491f20e6c57', 'A high-quality 3D render of a bored humanoid ape sitting in a dimly lit, luxurious underground clubhouse lounge. The ape has golden fur, wearing a vintage Hawaiian shirt and 3D glasses. He is holding a glass of glowing neon juice. Cinematic lighting, hyper-detailed textures, vibrant pop-art colors, 8k resolution, Unreal Engine 5 style.', 'doubao-seedream-5-0', '1:1', '4K', 'https://pub-8742eaa8e7ce488ba306c3dc5bacddd1.r2.dev/images/1775697781978-1775697781977-0.png', '2026-04-09T01:23:02.740Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('489333df-e1a4-4cf4-a913-262d7fc3e5e3', '33538287-6906-41c9-852a-9491f20e6c57', 'An ancient, enchanted library hidden inside a massive, hollowed-out tree trunk. Thousands of glowing books float in spirals, guided by bioluminescent pixies. Deep greens, blues, and warm gold tones. Magical atmosphere, intricate details, storybook illustration style.', 'doubao-seedream-4-5', '2:3', '4K', 'https://pub-8742eaa8e7ce488ba306c3dc5bacddd1.r2.dev/images/1775694908242-1775694908242-0.png', '2026-04-09T00:35:08.635Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('c28ec4cd-37e5-4350-9c29-7cd907d401be', '33538287-6906-41c9-852a-9491f20e6c57', 'A rebellious cyber-samurai with glowing blue neon katana standing on a rain-slicked rooftop overlooking a sprawling Neo-Tokyo. Her armor is a fusion of traditional lamellar and advanced carbon fiber. In the background, a massive digital cherry blossom tree blooms on a hologram screen. Anime style, high contrast, deep shadows.', 'doubao-seedream-4-5', '9:16', '4K', 'https://pub-8742eaa8e7ce488ba306c3dc5bacddd1.r2.dev/images/1775694881388-1775694881388-0.png', '2026-04-09T00:34:41.715Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('c1bb7680-fc6e-4fbf-883d-af110b3dfb3d', '33538287-6906-41c9-852a-9491f20e6c57', 'A majestic, iridescent Chinese dragon coiled around a towering, mist-shrouded mountain peak, breathing stylized clouds that morph into constellations. Below, a tiny, ancient temple clings to the cliffside. Vibrant watercolor and ink illustration, traditional Chinese art style mixed with modern fantasy.', 'doubao-seedream-5-0', '16:9', '4K', 'https://pub-8742eaa8e7ce488ba306c3dc5bacddd1.r2.dev/images/1775694842278-1775694842278-0.png', '2026-04-09T00:34:02.600Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('3acc11da-df57-4139-95f5-6124107c9457', '33538287-6906-41c9-852a-9491f20e6c57', 'A sprawling, neon-drenched futuristic megacity built within a massive canyon, inspired by Blade Runner. Flying vehicles (spinners) leave light trails as they navigate between towering skyscrapers draped in colossal holographic advertisements. A massive, bio-engineered artificial sun hangs above. Cinematic concept art, digital painting, epic scale.', 'doubao-seedream-5-0', '3:2', '4K', 'https://pub-8742eaa8e7ce488ba306c3dc5bacddd1.r2.dev/images/1775694776675-1775694776675-0.png', '2026-04-09T00:32:57.378Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('a8902671-3bab-44d2-8f9f-a0c85d69b8de', '33538287-6906-41c9-852a-9491f20e6c57', 'A hyper-realistic macro photograph of an intricate, gold-plated Mayan calendar stone discovered in a dense jungle. The stone is covered in ancient hieroglyphs and celestial carvings, partially enveloped by moss and vines. A faint stream of sunlight pierces through the canopy, highlighting the weathered textures. Shot on Sony A1, 85mm lens.', 'doubao-seedream-5-0', '2:3', '4K', 'https://pub-8742eaa8e7ce488ba306c3dc5bacddd1.r2.dev/images/1775694721895-1775694721895-0.png', '2026-04-09T00:32:03.208Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('d200ab62-4e44-40dc-b294-972f6a95cd75', '33538287-6906-41c9-852a-9491f20e6c57', 'A macro photography shot of a person''s fingers holding a tiny, detailed 3D pop-up sticker of New York City. The sticker features the Statue of Liberty, Brooklyn Bridge, Empire State Building, and yellow taxis on a blue river. The miniature city has a realistic, textured look. The background is a real, soft-focus, blurred cinematic New York City skyline during daytime. Natural lighting, high depth of field on the fingers and sticker, 8k resolution.', 'doubao-seedream-4-5', '2:3', '4K', 'https://pub-8742eaa8e7ce488ba306c3dc5bacddd1.r2.dev/images/1775653873693-1775653873693-0.png', '2026-04-08T13:11:15.212Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('b12e8511-01a6-4819-9861-724b74916fcd', '33538287-6906-41c9-852a-9491f20e6c57', 'A die-cut sticker design of New York City, featuring a collection of famous landmarks like the Statue of Liberty and skyscrapers. A human hand pinching the sticker, showcasing its small size. Flat design mixed with 3D depth, bright and saturated colors, blurred urban background, clear details, aesthetic and modern composition.', 'doubao-seedream-4-5', '3:4', '4K', 'https://eleai.22992af2b160c06666b8ca410aa4c0b2.r2.cloudflarestorage.com/images/1775653511565-1775653511565-0.png', '2026-04-08T13:05:13.005Z');
