INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('e2274906-7b0c-4604-a130-0a8cde060a46', '33538287-6906-41c9-852a-9491f20e6c57', 'Summer Design for ephemera collage clipart with a soft mixed-media style and playful layered elements. Perfect for scrapbooking, junk journals, and creative summer-themed design projects.', 'doubao-seedream-4-5', '1:1', '4K', 'https://ark-content-generation-v2-cn-beijing.tos-cn-beijing.volces.com/doubao-seedream-4-5/02177565198805192c12e7cc40d8c81c7b5e7f180fb09ed302784_0.jpeg?X-Tos-Algorithm=TOS4-HMAC-SHA256&X-Tos-Credential=AKLTYWJkZTExNjA1ZDUyNDc3YzhjNTM5OGIyNjBhNDcyOTQ%2F20260408%2Fcn-beijing%2Ftos%2Frequest&X-Tos-Date=20260408T124008Z&X-Tos-Expires=86400&X-Tos-Signature=50fa32350a05f470d69e64e771f5fea902aefdbb6ffc1f1424ee948c6bcb6b05&X-Tos-SignedHeaders=host', '2026-04-08T12:40:12.115Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('a287f106-7116-4b72-a271-7f56cc4b4b16', '33538287-6906-41c9-852a-9491f20e6c57', 'A powerful artistic prompt where the final image is fully controlled by a single variable. Instructions include diverse variable ideas to generate unique, non-repetitive visuals every time.', 'doubao-seedream-4-5', '3:4', '4K', 'https://ark-content-generation-v2-cn-beijing.tos-cn-beijing.volces.com/doubao-seedream-4-5/021775651592703ad114934056b0c06cfdb66f2980f6adc6e7c9f_0.jpeg?X-Tos-Algorithm=TOS4-HMAC-SHA256&X-Tos-Credential=AKLTYWJkZTExNjA1ZDUyNDc3YzhjNTM5OGIyNjBhNDcyOTQ%2F20260408%2Fcn-beijing%2Ftos%2Frequest&X-Tos-Date=20260408T123338Z&X-Tos-Expires=86400&X-Tos-Signature=3a50801ff2235cbfeccc67dc4bd9eebf1da83a3a911beb4a04894e250a04f943&X-Tos-SignedHeaders=host', '2026-04-08T12:33:41.866Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('4324f99f-47c3-462f-8258-ff86e5b63e10', '33538287-6906-41c9-852a-9491f20e6c57', 'Create a whimsical gnome with a long textured hat in a soft pastel birthday style. This prompt is perfect for generating cohesive magical clipart, nursery decor, and charming birthday illustrations with a dreamy watercolor aesthetic.', 'doubao-seedream-4-5', '3:4', '4K', '/aigenerate/1775642808539-0.png', '2026-04-08T10:06:48.550Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('88d18a59-ca20-43c3-9267-235a52a00825', '33538287-6906-41c9-852a-9491f20e6c57', '熊猫在宽敞的厨房里忙碌着，它戴着一顶可爱的厨师帽，身上系着一条蓝色的围裙。灶台上火焰升腾，锅里煮着热气腾腾的汤，熊猫正用勺子搅拌着。旁边的案板上放着切好的竹笋和青菜，它的双手沾满了面粉，正在准备包饺子，厨房的角落里堆满了新鲜的食材，背景虚化干净，32K，高清画质。', 'doubao-seedream-4-5', '3:4', '4K', '/aigenerate/1775546562846-0.png', '2026-04-07T07:22:42.854Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('5e33e8a9-d2c5-4225-8da6-747bf116e60c', '33538287-6906-41c9-852a-9491f20e6c57', '一只憨态可掬的熊猫，正端坐在温馨的家里弹奏琵琶。它身着一件绣有竹子图案的绿色长袍，毛茸茸的双手熟练地拨弄着琴弦。熊猫脸上洋溢着陶醉的神情，眼睛微闭，仿佛沉浸在美妙的音乐之中。房间布置简洁，摆放着几盆翠绿的竹子，背景虚化干净，32K，高清画质', 'doubao-seedream-4-5', '3:4', '4K', '/aigenerate/1775546524126-0.png', '2026-04-07T07:22:04.399Z');
INSERT INTO public.image_generations (id, user_id, prompt, model_id, aspect_ratio, quality, image_url, created_at) VALUES ('15fb3487-0ece-4860-8e72-372b17fdd1aa', '33538287-6906-41c9-852a-9491f20e6c57', '2 岁的可爱小萌娃，那黑色的大眼睛明亮而有神，仿佛藏着无尽的好奇与纯真，高鼻梁精致挺直，衬托出圆润的脸蛋更加可爱。额前的几缕碎发随风飘动，头上戴着一个粉色的小花环，32K，高清画质。', 'doubao-seedream-4-5', '3:4', '4K', '/aigenerate/1775546444695-0.png', '2026-04-07T07:20:44.702Z');
